mapper.select:
${pagingTop} SELECT homepage_id, popup_idx, popup_name, html, html_use_yn, popup_type, link_url, link_type, use_yn, print_seq, width, height, x_position, y_position, img_file_name, real_file_name, file_extension, file_size, add_date, link_target, start_date, end_date, common_yn, not_common FROM CMS_POPUP WHERE homepage_id = #{homepage_id}
AND ${search_type} LIKE '%'||#{search_text}||'%'
ORDER BY popup_type, add_date DESC ${pagingBottom}

mapper.insert:
SELECT NVL(MAX(popup_idx),0)+1 FROM CMS_POPUP WHERE homepage_id = #{homepage_id}
INSERT INTO CMS_POPUP ( homepage_id, popup_idx, popup_name, html, html_use_yn, popup_type, link_url, use_yn, print_seq, width, height, x_position, y_position, add_date, link_type, link_target, start_date, end_date, common_yn, not_common
, img_file_name, real_file_name, file_extension, file_size
) VALUES ( #{homepage_id}, #{popup_idx}, #{popup_name}, #{html}, #{html_use_yn}, #{popup_type}, #{link_url}, #{use_yn}, #{print_seq}, #{width}, #{height}, #{x_position}, #{y_position}, SYSDATE,#{link_type}, #{link_target}, #{start_date}, #{end_date}, #{common_yn}, #{not_common}
, #{img_file_name}, #{real_file_name}, #{file_extension}, #{file_size}
)

mapper.update:
UPDATE CMS_POPUP SET popup_name = #{popup_name}, html = #{html}, html_use_yn = #{html_use_yn}, popup_type = #{popup_type}, link_type = #{link_type}, link_url = #{link_url}, use_yn = #{use_yn}, print_seq = #{print_seq}, width = #{width}, height = #{height}, x_position = #{x_position}, y_position = #{y_position}, link_target = #{link_target}, start_date = #{start_date}, end_date = #{end_date}, common_yn = #{common_yn}, not_common = #{not_common}
,img_file_name = #{img_file_name}, real_file_name = #{real_file_name}, file_extension = #{file_extension}, file_size = #{file_size}
WHERE homepage_id = #{homepage_id} AND popup_idx = #{popup_idx}
